jest.mock('../../../modules/work_records');
// eslint-disable-next-line import/order -- should be after jest.mock
const {PeoSidecarService} = require('../../../modules/work_records');

const getWorkTypeMock = jest.fn().mockReturnValue('FULL_TIME');
const getFtePercentageMock = jest.fn().mockReturnValue(null);
const saveSidecarMock = jest.fn().mockResolvedValue(null);
PeoSidecarService.mockImplementation(() => ({
    getWorkType: getWorkTypeMock,
    getFtePercentage: getFtePercentageMock,
