    describe('updateDefaultPEOContractWithI9', () => {
        const profileId = 12345;
        const hrisProfileId = 67890;
        const clientLegalEntityId = 111;
        const oldContractId = 100;
        const newContractId = 200;

        let mockUpdatePEOContract;
        let mockGetDefaultContract;
        let mockUpdateNamesIfChangedOnHrisProfile;
        let mockLogInfo;

        const createDbMock = () => ({
            Contract: {
                findFirst: jest.fn(),
            },
            Sequelize: {
                Op: {notIn: 'notIn'},
            },
        });

        beforeEach(() => {
            mockUpdatePEOContract = jest.spyOn(peoContractService, 'updatePEOContract').mockResolvedValue({});
            mockGetDefaultContract = jest.spyOn(peoContractService, 'getDefaultContract');
            mockUpdateNamesIfChangedOnHrisProfile = jest
                .spyOn(peoContractService, 'updateNamesIfChangedOnHrisProfile')
                .mockResolvedValue();
            mockLogInfo = jest.spyOn(peoContractService.log, 'info').mockImplementation(() => {});
        });

        afterEach(() => {
            jest.restoreAllMocks();
        });

        describe('with explicit contractId', () => {
            it('should update the specified contract when contractId is provided', async () => {
                const targetContract = {
                    id: newContractId,
                    clientLegalEntityId,
                    HrisProfileId: hrisProfileId,
                };

                // Mock the db.Contract.findFirst to return the target contract
                peoContractService.db.Contract.findFirst = jest.fn().mockResolvedValue(targetContract);

                const i9Data = {
                    legalStatus: 'alien_authorized',
                    arnUscisNumber: 'A123456789',
                    authorizedToWorkUntil: '2025-12-31',
                    firstName: 'John',
                    lastName: 'Doe',
                    profileId,
                    contractId: newContractId,
                };

                await peoContractService.updateDefaultPEOContractWithI9(i9Data);

                // Should call findFirst with contractId filter
                expect(peoContractService.db.Contract.findFirst).toHaveBeenCalledWith(
                    expect.objectContaining({
                        where: expect.objectContaining({
                            id: newContractId,
                        }),
                    })
                );

                // Should NOT call getDefaultContract
                expect(mockGetDefaultContract).not.toHaveBeenCalled();

                // Should call updatePEOContract with correct payload
                expect(mockUpdatePEOContract).toHaveBeenCalledWith(
                    expect.objectContaining({
                        deelContractId: String(newContractId),
                        deelEntityId: String(clientLegalEntityId),
                        citizenStatus: 'Z04', // alien_authorized maps to Z04
                        i9AlienRegistrationNumber: 'A123456789',
                        i9AlienRegistrationExpiration: '2025-12-31',
                    })
                );
            });

            it('should throw error if contractId not found', async () => {
                peoContractService.db.Contract.findFirst = jest.fn().mockResolvedValue(null);

                const i9Data = {
                    legalStatus: 'citizen',
                    profileId,
                    contractId: 999999,
                };

                await expect(peoContractService.updateDefaultPEOContractWithI9(i9Data)).rejects.toThrow(
                    'PEO contract not found'
                );
            });
        });

        describe('without contractId (fallback)', () => {
            it('should use getDefaultContract when contractId not provided', async () => {
                const defaultContract = {
                    id: oldContractId,
                    clientLegalEntityId,
                    HrisProfileId: hrisProfileId,
                };

                mockGetDefaultContract.mockResolvedValue(defaultContract);

                const i9Data = {
                    legalStatus: 'citizen',
                    firstName: 'Jane',
                    lastName: 'Smith',
                    profileId,
                    // No contractId provided
                };

                await peoContractService.updateDefaultPEOContractWithI9(i9Data);

                // Should call getDefaultContract with profileId
                expect(mockGetDefaultContract).toHaveBeenCalledWith(profileId, ['id', 'clientLegalEntityId', 'HrisProfileId']);

                // Should call updatePEOContract with correct payload
                expect(mockUpdatePEOContract).toHaveBeenCalledWith(
                    expect.objectContaining({
                        deelContractId: String(oldContractId),
                        citizenStatus: 'Z01', // citizen maps to Z01
                    })
                );
            });
        });

        describe('citizen status mapping', () => {
            const testCases = [
                {legalStatus: 'citizen', expectedCitizenStatus: 'Z01'},
                {legalStatus: 'national_non_citizen', expectedCitizenStatus: 'Z02'},
                {legalStatus: 'permanent_resident', expectedCitizenStatus: 'Z03'},
                {legalStatus: 'alien_authorized', expectedCitizenStatus: 'Z04'},
            ];

            testCases.forEach(({legalStatus, expectedCitizenStatus}) => {
                it(`should map ${legalStatus} to ${expectedCitizenStatus}`, async () => {
                    mockGetDefaultContract.mockResolvedValue({
                        id: oldContractId,
                        clientLegalEntityId,
                        HrisProfileId: hrisProfileId,
                    });

                    await peoContractService.updateDefaultPEOContractWithI9({
                        legalStatus,
                        profileId,
                    });

                    expect(mockUpdatePEOContract).toHaveBeenCalledWith(
                        expect.objectContaining({
                            citizenStatus: expectedCitizenStatus,
                        })
                    );
                });
            });
        });

        describe('I-9 field handling', () => {
            it('should only include provided I-9 fields in payload', async () => {
                mockGetDefaultContract.mockResolvedValue({
                    id: oldContractId,
                    clientLegalEntityId,
                    HrisProfileId: hrisProfileId,
                });

                // Only provide some I-9 fields
                await peoContractService.updateDefaultPEOContractWithI9({
                    legalStatus: 'alien_authorized',
                    arnUscisNumber: 'A123456789',
                    // No authorizedToWorkUntil, i94Number, passportNumber, passportIssuingCountry
                    profileId,
                });

                expect(mockUpdatePEOContract).toHaveBeenCalledWith(
                    expect.objectContaining({
                        i9AlienRegistrationNumber: 'A123456789',
                    })
                );

                // These fields should NOT be present when not provided
                const calledPayload = mockUpdatePEOContract.mock.calls[0][0];
                expect(calledPayload).not.toHaveProperty('i9AlienRegistrationExpiration');
                expect(calledPayload).not.toHaveProperty('i94AdmissionNumber');
                expect(calledPayload).not.toHaveProperty('i9ForeignPassportNumber');
                expect(calledPayload).not.toHaveProperty('i9PassportIssuingCountry');
            });
        });
    });
